#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>

void demonstrate_fork() {
 printf("\n=== Demonstrating fork() ===\n");

 pid_t pid = fork();

 if (pid < 0) {
 // Fork failed
 perror("fork failed");
 exit(EXIT_FAILURE);
 }
 else if (pid == 0) {
 // Child process
 printf("CHILD: I am the child process\n");
 printf("CHILD: My PID = %d\n", getpid());
 printf("CHILD: Parent's PID = %d\n", getppid());
 printf("CHILD: fork() returned 0 to me\n");

 // Child sleeps for 1 second
 sleep(1);
 printf("CHILD: Exiting...\n");
 exit(42); // Exit with status 42
 }
 else {
 // Parent process
 int status;
 printf("PARENT: I am the parent process\n");
 printf("PARENT: My PID = %d\n", getpid());
 printf("PARENT: Child's PID = %d\n", pid);
 printf("PARENT: fork() returned child's PID to me\n");

 // Wait for child to terminate
 printf("PARENT: Waiting for child...\n");
 waitpid(pid, &status, 0);

 if (WIFEXITED(status)) {
 printf("PARENT: Child exited with status: %d\n", WEXITSTATUS(status));
 }
 printf("PARENT: Resuming execution after child\n");
 }
}

void demonstrate_fork_exec() {
 printf("\n=== Demonstrating fork() + exec() ===\n");

 pid_t pid = fork();

 if (pid < 0) {
 perror("fork failed");
 exit(EXIT_FAILURE);
 }
 else if (pid == 0) {
 // Child process - replace with new program
 printf("CHILD: About to replace myself with 'ls -la'\n");

 // execlp searches PATH for the executable
 execlp("ls", "ls", "-la", NULL);

 // If exec returns, an error occurred
 perror("exec failed");
 exit(EXIT_FAILURE);
 }
 else {
 // Parent waits for child
 wait(NULL);
 printf("PARENT: Child finished executing 'ls -la'\n");
 }
}

int main() {
 printf("Process Operations Demonstration\n");
 printf("================================\n");
 printf("Initial PID: %d\n", getpid());

 // Demonstrate basic fork
 demonstrate_fork();

 // Demonstrate fork + exec
 demonstrate_fork_exec();

 printf("\n=== All demonstrations complete ===\n");
 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <signal.h>
#include <string.h>

void demonstrate_zombie() {
 printf("\n=== Demonstrating Zombie Process ===\n");
 printf("A zombie occurs when child terminates but parent hasn't called wait()\n");
 printf("Press Ctrl+C after seeing zombie (or wait 5 seconds)\n\n");

 pid_t pid = fork();

 if (pid == 0) {
 // Child process
 printf("CHILD (PID %d): Starting, will exit soon...\n", getpid());
 sleep(1);
 printf("CHILD (PID %d): Exiting now\n", getpid());
 exit(0); // Child terminates
 }
 else if (pid > 0) {
 // Parent process
 printf("PARENT (PID %d): Created child PID %d\n", getpid(), pid);
 printf("PARENT: NOT calling wait() - child will become zombie\n");
 printf("PARENT: Sleeping to let child terminate...\n");

 // Check process state using ps command
 sleep(2);
 printf("PARENT: Checking for zombie process with ps command...\n");
 fflush(stdout);
 system("ps -o pid,ppid,state,cmd | grep Z\|defunct || echo 'No zombie visible'\n");

 printf("PARENT: Now calling wait() to collect child's exit status\n");
 int status;
 waitpid(pid, &status, 0);
 printf("PARENT: Successfully collected child (status=%d)\n", WEXITSTATUS(status));
 printf("PARENT: Zombie is now reaped (OS freed PCB)\n");
 }
}

void demonstrate_orphan() {
 printf("\n=== Demonstrating Orphan Process ===\n");
 printf("An orphan is a child whose parent has terminated\n");
 printf("Orphans are adopted by init (PID 1)\n\n");

 pid_t pid = fork();

 if (pid == 0) {
 // Child process
 printf("CHILD (PID %d): My parent is %d\n", getpid(), getppid());

 // Wait a bit for parent to terminate
 sleep(3);

 // Check new parent
 printf("CHILD (PID %d): 3 seconds later, my parent is now %d\n",
 getpid(), getppid());

 if (getppid() == 1) {
 printf("CHILD: Adopted by init (PID 1) - I am an orphan!\n");
 }

 sleep(1);
 printf("CHILD: Exiting\n");
 exit(0);
 }
 else {
 // Parent process
 printf("PARENT (PID %d): Created child PID %d\n", getpid(), pid);
 printf("PARENT: Will terminate immediately, making child orphan\n");
 exit(0); // Parent exits - child becomes orphan
 }
}

int main(int argc, char *argv[]) {
 printf("Zombie and Orphan Process Demonstration\n");
 printf("=========================================\n\n");

 // Demonstrate zombie process
 demonstrate_zombie();

 sleep(1);

 // Demonstrate orphan process
 // This creates a daemon-like process
 pid_t pid = fork();

 if (pid == 0) {
 // This child will become orphan
 printf("ORPHAN CHILD: Running in background, parent exited\n");
 printf("ORPHAN CHILD: Will be adopted by init\n");
 sleep(2);
 printf("ORPHAN CHILD: My new parent is %d\n", getppid());
 sleep(1);
 printf("ORPHAN CHILD: Exiting\n");
 exit(0);
 }
 else {
 // Original parent exits
 printf("ORIGINAL PARENT: Exiting, child will become orphan\n");
 }

 // Wait a bit then check for any remaining processes
 sleep(3);
 printf("\n=== Demonstration Complete ===\n");
 return 0;
}
